vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

tim=(min(q17,uTime)/(18+(2/(audioMidSmooth+audioHigh))));
tcos=cos(tim);
tsin=sin(tim);
psin=1-(1-progress);
pcos=(1-progress);

    // sample previous uFrame
      // sample jpegs
li1 = texture(sampler_fw_rand01, vUvOriginal ).xyz*.5+.5*tcos*psin;
li2 = texture(sampler_pw_rand02, vUvOriginal ).xyz*.5+.5*tsin*psin;
li3 = texture(sampler_pc_rand03, vUvOriginal ).xyz*.5+.5*tcos*pcos;
li4 = texture(sampler_fc_rand04, vUvOriginal ).xyz*.5+.5*tsin*pcos;
      //mix em

cmix=max(li1,max(li2,max(li3,li4)));
cmin=max((min(li2,li4)*.5)*tsin,(min(li1,li3)*.5)*tcos);
cmcos = (1.5-vRadius)+5.5+(.5*tcos)+vec3(1/3,2/3,3/3);
cmcos.x -=int(cmcos.x);
cmcos.y -=int(cmcos.y);
cmcos.z -=int(cmcos.z);

ret =1.1*(GetMain (vUv))*(.2*mix(cmix,1-cmin,vRadius*.25+.019*max(psin,max(pcos,max(tsin,tcos)))));
ret-=.365;
 ret*=-.2+ret+(GetBlur3 (vUv));;

ret=ret*.5-.05*tcos;

  ret +=.35*(GetBlur3 (vUv))-.264*cmin.xyz*(cmcos+.4-ret);

    // darken (decay) over uTime
    //ret *= (0.65+.01351*cmcos); //or try: ret -= 0.004;
    //add em//+(GetBlur3 (vUv));
   ret+= .3013*texture( sampler_main, vUv ).xyz/(ret*2);
   ret -=.134*cmix-(.164*ret);


  fragColor = ret;
}
